def main():
    for tier, key in (('literal','L'), ('mediating','M'), ('thought','T')):
        data = load(tier, 'luke')
        for ch, verses in LUKE_7_9.items():
            data[ch] = {v: d[key] for v, d in verses.items()}
        save(tier, 'luke', data)
    print('Luke chapters 7-9 written.')

